const uniqueIndex = indexes.find(i => i.sql?.includes('UNIQUE') && i.sql.includes('lesson_plan_id') && i.sql.includes('objective_index'))
if (uniqueIndex && !uniqueIndex.sql?.includes('question_index')) {
