  text: string
  topic: string
}

export interface DocumentSummary {
  id: number
  filename: string
  title: string
  markdown_chars: number
  status: 'processing' | 'ready' | 'failed' | 'uploaded'
  error: string | null
  created_at: string
  plan: {
