import { useNavigate } from 'react-router-dom'
import { Clock, FileText, Loader2, AlertTriangle, RefreshCw, ChevronRight, Layers, Trash2 } from 'lucide-react'
import { cn } from '#lib/utils'
import { Badge } from '#components/ui/badge'
import { Button } from '#components/ui/button'
import type { DocumentSummary } from '#lib/types'
import { difficultyLabel, formatDate } from '#lib/format'

interface Props {
  doc: DocumentSummary
  onStartLearning?: (documentId: number) => void
  onDelete?: (documentId: number) => void
}

export function DocumentCard({ doc, onStartLearning, onDelete }: Props) {
  const navigate = useNavigate()
  const ready = doc.status === 'ready'
  const processing = doc.status === 'processing'
  const failed = doc.status === 'failed'

  const start = () => {
    if (doc.plan) {
      navigate(`/learn/${doc.plan.id}`)
    } else if (onStartLearning) {
      onStartLearning(doc.id)
    }
  }

  const title = doc.title || doc.filename.replace(/\.pdf$/i, '')

  return (
    <div className="group flex flex-col rounded-2xl border border-border bg-card p-5 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
      <div className="flex items-start gap-3">
        <div
          className={cn(
            'flex size-11 shrink-0 items-center justify-center rounded-xl',
            ready
              ? 'bg-primary/10 text-primary'
              : processing
                ? 'bg-accent text-accent-foreground'
                : 'bg-danger/10 text-danger'
          )}
        >
          {processing ? (
            <Loader2 className="size-5 animate-spin" />
          ) : failed ? (
            <AlertTriangle className="size-5" />
          ) : (
            <FileText className="size-5" />
          )}
        </div>
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold" title={title}>
            {title}
          </p>
          <p className="truncate text-xs text-muted-foreground" title={doc.filename}>
            {doc.filename}
          </p>
        </div>
        {doc.plan && <Badge variant="secondary">{difficultyLabel(doc.plan.difficulty)}</Badge>}
      </div>

      <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        <span className="inline-flex items-center gap-1">
          <Clock className="size-3.5" />
          {formatDate(doc.created_at)}
        </span>
        {ready && (
          <span className="inline-flex items-center gap-1">
            <FileText className="size-3.5" />
            {doc.markdown_chars.toLocaleString()} chars
          </span>
        )}
        {doc.attemptCount > 0 && (
          <span className="inline-flex items-center gap-1">
            <Layers className="size-3.5" />
            {doc.attemptCount} attempt{doc.attemptCount > 1 ? 's' : ''}
          </span>
        )}
      </div>

      {failed && (
        <p className="mt-3 line-clamp-2 rounded-md bg-danger/10 px-2.5 py-1.5 text-xs text-danger">
          {doc.error ?? 'Failed to process PDF'}
        </p>
      )}

      <div className="mt-4 flex items-center gap-2">
        {ready && !doc.plan && (
          <Button size="sm" className="gap-1.5" onClick={start}>
            Start learning
            <ChevronRight className="size-3.5" />
          </Button>
        )}
        {ready && doc.plan && (
          <>
            <Button size="sm" className="gap-1.5" onClick={start}>
              {doc.attemptCount > 0 ? (
                <>
                  <RefreshCw className="size-3.5" />
                  Retake
                </>
              ) : (
                <>
                  Continue
                  <ChevronRight className="size-3.5" />
                </>
              )}
            </Button>
            {doc.attemptCount > 0 && (
              <Button size="sm" variant="ghost" className="gap-1.5" onClick={start}>
                Review plan
              </Button>
            )}
          </>
        )}
        {processing && (
          <Button size="sm" variant="outline" disabled className="gap-1.5">
            <Loader2 className="size-3.5 animate-spin" />
            Parsing...
          </Button>
        )}
        {onDelete && (
          <Button
            size="sm"
            variant="ghost"
            className="ml-auto gap-1.5 text-danger hover:text-danger hover:bg-danger/10"
            onClick={() => {
              if (window.confirm(`Delete "${doc.title || doc.filename}"? This will remove all associated lesson plans and quiz attempts.`)) {
                onDelete(doc.id)
              }
            }}
          >
            <Trash2 className="size-3.5" />
          </Button>
        )}
      </div>
    </div>
  )
}

import path from 'node:path'
import { unlink } from 'node:fs/promises'
import { nanoid } from 'nanoid'
import { db, type DocumentRow } from '../db.ts'
import { convertPdfToMarkdown } from './pdf-to-markdown.ts'
import { UPLOADS_DIR } from '../config.ts'

type DocumentListItem = Omit<DocumentRow, 'stored_filename' | 'filepath' | 'markdown'>

interface PlanSummaryRow {
  id: number
  difficulty: string
  status: string
}

export async function listDocuments() {
  const rows = db
    .prepare(
      `SELECT id, filename, title, markdown_chars, status, error, created_at
       FROM documents ORDER BY datetime(created_at) DESC`
    )
    .all() as DocumentListItem[]

  return rows.map((r) => {
    const planRow = db
      .prepare(
        `SELECT id, difficulty, status FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC LIMIT 1`
      )
      .get(r.id) as PlanSummaryRow | undefined

    const attemptResult = db
      .prepare(
        `SELECT COUNT(*) AS c FROM attempts a JOIN lesson_plans p ON p.id = a.lesson_plan_id WHERE p.document_id = ?`
      )
      .get(r.id) as { c: number }

    const attemptCount = attemptResult.c
    return {
      ...r,
      plan: planRow
        ? {
            id: planRow.id,
            difficulty: planRow.difficulty,
            status: planRow.status
          }
        : null,
      attemptCount
    }
  })
}

export async function getDocument(id: number) {
  const row = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(id) as DocumentRow | undefined
  if (!row) return null
  return {
    id: row.id,
    filename: row.filename,
    title: row.title,
    status: row.status,
    markdown_chars: row.markdown_chars,
    created_at: row.created_at,
    error: row.error
  }
}

type Markdown = { markdown: string | null } | undefined

export async function getDocumentMarkdown(id: number): Promise<string | null> {
  const row = db.prepare(`SELECT markdown FROM documents WHERE id = ?`).get(id) as Markdown
  return row?.markdown ?? null
}

export async function uploadAndConvert(filename: string, buffer: Buffer): Promise<DocumentRow> {
  const storedFilename = `${Date.now()}-${nanoid(8)}-${filename.replace(/[^a-zA-Z0-9.\-_ ]/g, '')}`
  const filepath = path.join(UPLOADS_DIR, storedFilename)
  const { writeFile } = await import('node:fs/promises')
  await writeFile(filepath, buffer)

  const doc = db
    .prepare(
      `INSERT INTO documents (filename, stored_filename, filepath, status)
       VALUES (?, ?, ?, 'processing')
       RETURNING *`
    )
    .get(filename, storedFilename, filepath) as DocumentRow

  const result = await convertPdfToMarkdown(filepath)
  if (!result.ok) {
    db.prepare(`UPDATE documents SET status = 'failed', error = ? WHERE id = ?`).run(
      result.error ?? 'Unknown error',
      doc.id
    )
    throw Error('Error occured while converting PDF to markdown')
  }

  db.prepare(`UPDATE documents SET status = 'ready', markdown = ?, markdown_chars = ?, error = NULL WHERE id = ?`).run(
    result.markdown,
    result.markdown.length,
    doc.id
  )
  return doc
}

export async function deleteDocument(id: number): Promise<boolean> {
  const row = db.prepare(`SELECT filepath FROM documents WHERE id = ?`).get(id) as { filepath: string } | undefined
  if (!row) return false

  try {
    await unlink(row.filepath)
  } catch {
    // File may already be missing; proceed with DB cleanup
  }

  db.prepare(`DELETE FROM documents WHERE id = ?`).run(id)
  return true
}

