```ts
const statuses: ObjectiveStatus[] = plan.objectives.map((obj, objectiveIndex) => {
  let correct = 0
  let finalized = 0
  for (let q = 0; q < obj.question_count; q++) {
    const a = answers[slotKey(objectiveIndex, q)]
    if (a?.finalized) finalized += 1
    if (a?.correct) correct += 1
