  if (currentIdx + 1 >= slots.length) {
    void finish()
  } else {
    setCurrentIdx((i) => i + 1)
  }
}, [currentIdx, plan, slots.length, finish])

const handleIncorrect = useCallback(
  (key: string, learnerIndex: number) => {
    setAnswers((prev) => {
      const quizId = quizzes[key]?.id ?? -1
      const existing = prev[key] ?? blankAnswer(quizId)
      return {
        ...prev,
        [key]: {
          ...existing,
          quizId,
          learnerIndex,
          correct: false,
          attempts: existing.attempts + 1,
          finalized: false
        }
      }
    })
  },
  [quizzes]
)

const handleCorrect = useCallback(
  (key: string, learnerIndex: number) => {
    setAnswers((prev) => {
      const quizId = quizzes[key]?.id ?? -1
      const existing = prev[key] ?? blankAnswer(quizId)
      return {
        ...prev,
        [key]: {
          ...existing,
          quizId,
          learnerIndex,
          correct: true,
          // attempts stays — counts only incorrect tries
          finalized: true
        }
      }
    })
  },
  [quizzes]
)

const handleSkip = useCallback(
  (key: string) => {
    const quizId = quizzes[key]?.id ?? -1
    const existing = answers[key] ?? blankAnswer(quizId)
    const nextAnswers = {
      ...answers,
      [key]: {
        ...existing,
        quizId,
        learnerIndex: null,
        correct: false,
        finalized: true
      }
    }
    setAnswers(nextAnswers)
    if (currentIdx + 1 >= slots.length) {
      void finish(nextAnswers)
    } else {
      setCurrentIdx((i) => i + 1)
    }
  },
  [quizzes, answers, currentIdx, slots.length, finish]
)

